// ===================== SIDE DRAWER =====================
const sideDrawer = document.getElementById('sideDrawer');
const sideDrawerOverlay = document.getElementById('sideDrawerOverlay');

function openDrawer() {
    sideDrawer.classList.add('open');
    sideDrawerOverlay.classList.add('open');
}
function closeDrawer() {
    sideDrawer.classList.remove('open');
    sideDrawerOverlay.classList.remove('open');
}
document.getElementById('menuToggleBtn').addEventListener('click', openDrawer);
document.getElementById('drawerCloseBtn').addEventListener('click', closeDrawer);
sideDrawerOverlay.addEventListener('click', closeDrawer);

// ===================== GENERIC MODAL HELPERS =====================
function openModal(id) {
    document.getElementById(id).classList.add('open');
}
function closeModal(id) {
    document.getElementById(id).classList.remove('open');
}
document.querySelectorAll('.modal-overlay').forEach(overlay => {
    overlay.addEventListener('click', (e) => {
        if (e.target === overlay) overlay.classList.remove('open');
    });
});
document.querySelectorAll('.modal-close').forEach(btn => {
    btn.addEventListener('click', () => btn.closest('.modal-overlay').classList.remove('open'));
});

// ===================== SOCIAL POPUP =====================
function showSocialModal(key) {
    const data = SOCIALS[key];
    if (!data) return;
    document.getElementById('socialModalIcon').innerHTML = `<i class="${data.icon}"></i>`;
    document.getElementById('socialModalTitle').textContent = data.label + " Profile";
    document.getElementById('socialModalHandle').textContent = data.handle;
    document.getElementById('socialModalLink').textContent = data.url;
    const redirectBtn = document.getElementById('socialModalRedirect');
    redirectBtn.href = data.url;
    redirectBtn.target = "_blank";
    redirectBtn.rel = "noopener noreferrer";
    openModal('socialModal');
    closeDrawer();
}

document.querySelectorAll('[data-social]').forEach(el => {
    el.addEventListener('click', (e) => {
        e.preventDefault();
        showSocialModal(el.getAttribute('data-social'));
    });
});

// ===================== ALL SOCIAL LINKS MODAL (from drawer) =====================
function renderAllSocialsModal() {
    const wrap = document.getElementById('allSocialsGrid');
    wrap.innerHTML = '';
    Object.keys(SOCIALS).forEach(key => {
        const s = SOCIALS[key];
        const item = document.createElement('button');
        item.className = 'side-drawer-item';
        item.style.border = '1px solid var(--border-color)';
        item.innerHTML = `<span class="side-drawer-item-icon"><i class="${s.icon}"></i></span> ${s.label}`;
        item.addEventListener('click', () => {
            closeModal('allSocialsModal');
            showSocialModal(key);
        });
        wrap.appendChild(item);
    });
}

