// ===================== TOAST =====================
function showToast(msg) {
    const toast = document.getElementById('toast');
    toast.textContent = msg;
    toast.classList.add('show');
    setTimeout(() => toast.classList.remove('show'), 2200);
}

// ===================== RENDER REPOS =====================
function renderRepos() {
    const container = document.getElementById('repos-container');
    container.innerHTML = '';
    REPOS.forEach((repo, i) => {
        const card = document.createElement('div');
        card.className = 'repo-card';
        card.style.animationDelay = (i * 0.08) + 's';
        card.innerHTML = `
            <a href="${repo.url}" target="_blank" rel="noopener noreferrer" class="repo-name">
                <i class="fa-solid fa-book repo-icon"></i> ${repo.name}
            </a>
            <p class="repo-description">${repo.desc}</p>
            <div class="repo-tags">
                ${repo.tags.map(t => `<span class="repo-tag">${t}</span>`).join('')}
            </div>
            <div class="repo-stats">
                <span class="repo-stat"><i class="fa-regular fa-star"></i> ${repo.stars}</span>
                <span class="repo-stat"><i class="fa-solid fa-code-fork"></i> ${repo.forks}</span>
            </div>
        `;
        container.appendChild(card);
    });
    const moreCard = document.createElement('div');
    moreCard.className = 'repo-card';
    moreCard.innerHTML = `
        <a href="https://github.com/kr1shnavishwakarma?tab=repositories" target="_blank" rel="noopener noreferrer" class="repo-name">
            <i class="fa-solid fa-diagram-project repo-icon"></i> View all 84 repositories
        </a>
        <p class="repo-description">See the complete list of repositories on GitHub, including experiments, forks, and archived work.</p>
    `;
    container.appendChild(moreCard);
}

// ===================== COUNTERS =====================
function animateCount(el, target, isDecimalK) {
    const duration = 1200;
    const start = performance.now();
    function step(now) {
        const progress = Math.min((now - start) / duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);
        if (isDecimalK) {
            const val = (target * eased).toFixed(2);
            el.textContent = val + 'k';
        } else {
            el.textContent = Math.floor(target * eased);
        }
        if (progress < 1) requestAnimationFrame(step);
        else el.textContent = isDecimalK ? target.toFixed(2) + 'k' : target;
    }
    requestAnimationFrame(step);
}

