// Escape key closes drawer/modals
document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
        closeDrawer();
        document.querySelectorAll('.modal-overlay.open').forEach(m => m.classList.remove('open'));
    }
});
